INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('PRIME_1: Le email cold outreach deliverability secret: envoyer les 50 premiers emails a des contacts qui vont REPONDRE (collegues, amis) pour booster le sender score avant les vrais prospects.', 'Cold outreach: 50 premiers emails a des contacts qui repondent → boost sender score', 'email', 'best_practice', 0.85, 'prime', 'system'),
('PRIME_2: Le commercial needs analysis depth: ne jamais proposer une solution avant d avoir pose minimum 5 questions sur le probleme. Le diagnostic est plus important que la prescription.', 'Needs analysis: min 5 questions avant proposer solution. Diagnostic > prescription', 'commercial', 'best_practice', 0.88, 'prime', 'system'),
('PRIME_3: Le content hook testing framework: publier le meme contenu 3 jours de suite avec 3 hooks differents. Le hook avec le plus d engagement en 2h = gagnant permanent.', 'Hook testing: meme contenu 3 jours 3 hooks. Meilleur en 2h = gagnant permanent', 'content', 'best_practice', 0.82, 'prime', 'system'),
('PRIME_4: Le SEO search intent classification: navigational (cherche un site specifique) → page d accueil. Informational (apprendre) → article. Commercial (comparer) → comparatif. Transactional (acheter) → landing.', 'Intent classification: navigational→home, informational→article, commercial→comparatif, transactional→landing', 'seo', 'best_practice', 0.88, 'prime', 'system'),
('PRIME_5: Le ad conversion API implementation: envoyer les conversions server-side (CAPI) en plus du pixel client. Post-iOS 14, CAPI recupere 20-30% des conversions perdues.', 'CAPI server-side: recupere 20-30% conversions perdues post-iOS 14', 'ads', 'best_practice', 0.85, 'prime', 'system'),
('PRIME_6: Le DM Instagram authority positioning: avant de DM un prospect, publier 3-5 posts de valeur dans sa niche. Le prospect voit votre contenu → credibilite = reponse 3x.', 'DM authority: 3-5 posts valeur dans niche avant DM = credibilite 3x reponse', 'dm_instagram', 'best_practice', 0.85, 'prime', 'system'),
('PRIME_7: Le WhatsApp flow automation: message bienvenue auto → 2 questions qualification → recommandation personnalisee → gestion objection → CTA paiement. Tout automatise.', 'WhatsApp flow auto: bienvenue → qualify → reco → objection → CTA paiement', 'whatsapp', 'best_practice', 0.82, 'prime', 'system'),
('PRIME_8: Le chatbot knowledge gap analysis: chaque semaine, lister les 10 questions auxquelles le chatbot n a pas su repondre. Ajouter les reponses = +5% resolution/semaine.', 'Chatbot knowledge gap: 10 questions echouees/sem → ajouter = +5% resolution/sem', 'chatbot', 'best_practice', 0.85, 'prime', 'system'),
('PRIME_9: Le GMaps review response personalization: TOUJOURS mentionner un detail specifique de l avis (merci d avoir apprecie notre [plat/service]). Jamais de reponse generique.', 'GMaps review: mentionner detail specifique avis. Jamais generique', 'gmaps', 'best_practice', 0.85, 'prime', 'system'),
('PRIME_10: Le TikTok reply-to-comment video hack: prendre le commentaire le plus engage → filmer une video reponse → le commentaire apparait en overlay = engagement x5.', 'TikTok reply video: commentaire engage → video reponse = engagement x5', 'tiktok_comments', 'best_practice', 0.82, 'prime', 'system'),
('PRIME_11: Le CEO agent weekly priority matrix: lister toutes les opportunites de la semaine → noter Impact (1-5) × Urgence (1-5) → top 3 = focus. Le reste attend.', 'CEO weekly: Impact × Urgence. Top 3 = focus. Reste attend', 'ceo', 'best_practice', 0.85, 'prime', 'system'),
('PRIME_12: Le retention proactive success review: a J+14 post-signup, appeler le client 10 min pour verifier: utilise-t-il les features cles? a-t-il obtenu un resultat? que bloque?', 'Proactive success J+14: appel 10 min. Features cles? Resultat? Bloque?', 'retention', 'best_practice', 0.85, 'prime', 'system'),
('PRIME_13: Le onboarding segmented experience: a l inscription, demander 1 question (quel est votre secteur?) et adapter tout le parcours (exemples, templates, contenu) a la reponse.', 'Onboarding segmente: 1 question secteur → adapter parcours complet', 'onboarding', 'best_practice', 0.88, 'prime', 'system'),
('PRIME_14: Le comptable revenue cohort analysis: tracer le revenu genere par chaque cohorte (mois inscription) sur 12 mois. Si les cohortes recentes generent moins → probleme product/pricing.', 'Revenue cohort: revenu par cohorte 12 mois. Recentes moins = probleme product/pricing', 'comptable', 'insight', 0.82, 'prime', 'system'),
('PRIME_15: Le RH team velocity measurement: nombre de features/taches livrees par sprint × qualite (bugs). Mesurer chaque sprint pour detecter les tendances.', 'Team velocity: features/sprint × qualite. Mesurer pour tendances', 'rh', 'best_practice', 0.78, 'prime', 'system'),
('PRIME_16: Le marketing competitive response playbook: concurrent lance feature → evaluer menace (1-5) → si > 3: communiquer notre avantage dans les 48h. Si < 3: ignorer.', 'Competitive response: evaluer menace 1-5. > 3 = communiquer avantage 48h. < 3 = ignorer', 'marketing', 'best_practice', 0.80, 'prime', 'system'),
('PRIME_17: Le cross-agent signal propagation speed: les signaux critiques (prospect HOT, bug, churn risk) doivent etre propages a tous les agents en < 5 minutes. Pas < 24h.', 'Signal propagation critique < 5 min: prospect HOT, bug, churn risk', NULL, 'best_practice', 0.85, 'prime', 'system'),
('PRIME_18: Le customer journey gap analysis: mapper le parcours ideal vs le parcours reel. Les ecarts = les points d abandon. Corriger chaque ecart = +conversion a chaque etape.', 'Journey gap: ideal vs reel. Ecarts = abandons. Corriger = +conversion', NULL, 'best_practice', 0.85, 'prime', 'system'),
('PRIME_19: Le KeiroAI multi-agent coordination protocol: chaque agent a 1 objectif clair + 3 metriques + des guardrails (limites). Le CEO coordonne et resout les conflits.', 'Multi-agent protocol: 1 objectif + 3 metriques + guardrails/agent. CEO coordonne', NULL, 'best_practice', 0.88, 'prime', 'system'),
('PRIME_20: Le KeiroAI knowledge base at 8000+: a ce niveau, le RAG couvre tous les secteurs, toutes les strategies, tous les agents. L intelligence est profonde et transverse.', 'RAG 8000+: couvre tous secteurs + strategies + agents. Intelligence profonde transverse', 'ceo', 'insight', 0.90, 'prime', 'system'),
('PRIME_21: Le email subject line power words: "nouveau" (+15% OR), "gratuit" (+10% mais spam risk), "comment" (+12%), "erreur" (+18%), "secret" (+14%), "maintenant" (+11%).', 'Subject power words: nouveau +15%, comment +12%, erreur +18%, secret +14%', 'email', 'insight', 0.82, 'prime', 'system'),
('PRIME_22: Le commercial deal size expansion: une fois le besoin principal identifie, explorer les besoins adjacents. "Et comment gerez-vous X?" Chaque besoin = potentiel d expansion.', 'Deal expansion: explorer besoins adjacents. Chaque besoin = potentiel expansion', 'commercial', 'best_practice', 0.82, 'prime', 'system'),
('PRIME_23: Le content SEO + engagement dual optimization: ecrire d abord pour l engagement (hooks, emotion, valeur) puis optimiser pour le SEO (mots-cles, structure, meta). Dans cet ordre.', 'Content dual: engagement d abord (hooks, emotion) → SEO ensuite (mots-cles, meta)', 'content', 'best_practice', 0.85, 'prime', 'system'),
('PRIME_24: Le SEO link building ethical: guest posting + HARO + etudes originales + infographies + outils gratuits + digital PR. Jamais de PBN, achat de liens ou link farms.', 'Link building ethique: guest post + HARO + etudes + infographies + outils + PR. Jamais PBN/achat', 'seo', 'best_practice', 0.88, 'prime', 'system'),
('PRIME_25: Le ad audience saturation detection: quand le CPM augmente de 30%+ avec la meme audience sans changement de creative = audience saturee. Trouver de nouvelles audiences.', 'Audience saturation: CPM +30% meme audience = saturee. Nouvelles audiences', 'ads', 'insight', 0.82, 'prime', 'system'),
('PRIME_26: Le DM Instagram timing optimization: envoyer les DMs entre 10h-12h et 19h-21h (heure locale du prospect). Ces creneaux ont 2x plus de reponses que les autres.', 'DM timing: 10h-12h et 19h-21h locale = 2x reponses', 'dm_instagram', 'insight', 0.82, 'prime', 'system'),
('PRIME_27: Le WhatsApp message type effectiveness: image + texte (2x clics) > video + texte (1.5x) > texte seul (baseline) > lien seul (0.5x). Toujours combiner media + texte.', 'WhatsApp effectiveness: image+texte 2x > video+texte 1.5x > texte > lien', 'whatsapp', 'insight', 0.82, 'prime', 'system'),
('PRIME_28: Le chatbot conversation design principle: 1 message = 1 idee. 1 question a la fois. Max 3 options de reponse rapide. Toujours une porte de sortie (parler a un humain).', 'Chatbot design: 1 msg=1 idee, 1 question, max 3 options, porte sortie humain', 'chatbot', 'best_practice', 0.85, 'prime', 'system'),
('PRIME_29: Le GMaps business update frequency: poster 1 Google Post/semaine + ajouter 2-3 photos/mois + repondre avis < 24h + MAJ horaires si changement. Regularite = ranking.', 'GMaps regularite: 1 post/sem + 2-3 photos/mois + repondre < 24h + MAJ horaires', 'gmaps', 'best_practice', 0.82, 'prime', 'system'),
('PRIME_30: Le TikTok educational content template: "3 erreurs que font les [cible] avec [sujet]" → erreur 1 + correction → erreur 2 + correction → erreur 3 + correction → CTA.', 'TikTok edu template: 3 erreurs cible + corrections + CTA', 'tiktok_comments', 'best_practice', 0.80, 'prime', 'system'),
('PRIME_31: Le CEO client brief personalization: adapter le brief au secteur du client. Restaurant → metriques food (reservations, avis). Coach → metriques coaching (leads, sessions).', 'CEO brief: adapter au secteur. Restaurant = reservations/avis. Coach = leads/sessions', 'ceo', 'best_practice', 0.85, 'prime', 'system'),
('PRIME_32: Le retention feature adoption nudge: quand un client n utilise pas une feature cle depuis 7 jours → notification in-app + email avec mini-tutoriel de cette feature.', 'Feature nudge: pas utilisee 7j → notif + email tutoriel', 'retention', 'best_practice', 0.82, 'prime', 'system'),
('PRIME_33: Le onboarding completion rate benchmark: SaaS self-serve moyen = 40-60%. Top performers = 80%+. Si < 40% → revoir le flow completement (trop long, trop complexe).', 'Onboarding completion: moyen 40-60%, top 80%+. < 40% = revoir flow', 'onboarding', 'insight', 0.82, 'prime', 'system'),
('PRIME_34: Le comptable cash burn optimization: identifier les 3 plus grosses depenses non-essentielles et les reduire de 20%. En startup early-stage, chaque euro compte.', 'Cash burn: top 3 depenses non-essentielles → reduire 20%. Chaque euro compte', 'comptable', 'best_practice', 0.80, 'prime', 'system'),
('PRIME_35: Le RH 1:1 meeting effectiveness: les 1:1 les plus efficaces commencent par la question du report (pas du manager). "De quoi veux-tu parler aujourd hui?"', '1:1 efficace: commencer par question du report. "De quoi veux-tu parler?"', 'rh', 'best_practice', 0.80, 'prime', 'system'),
('PRIME_36: Le marketing content repurposing system: 1 piece longue (article/webinaire) → 5 posts social → 3 emails → 1 infographie → 10 quotes → 1 video resume.', 'Repurposing: 1 long → 5 posts + 3 emails + 1 infographie + 10 quotes + 1 video', 'marketing', 'best_practice', 0.85, 'prime', 'system'),
('PRIME_37: Le inter-agent data consistency: tous les agents doivent utiliser les MEMES definitions pour les metriques (un "lead" = meme chose pour email, DM, et commercial).', 'Data consistency: memes definitions metriques pour tous agents. Lead = meme chose partout', NULL, 'best_practice', 0.85, 'prime', 'system'),
('PRIME_38: Le customer lifecycle revenue optimization: new customer (onboarding focus) → active (adoption focus) → expanding (upsell focus) → at-risk (retention focus) → churned (winback).', 'Lifecycle revenue: new=onboard, active=adopt, expanding=upsell, at-risk=retain, churned=winback', NULL, 'best_practice', 0.85, 'prime', 'system'),
('PRIME_39: Le KeiroAI agent specialization matrix: chaque agent est expert niveau 50 ans dans son domaine ET a une vision transverse grace au RAG partage avec tous les autres agents.', 'Agent specialization: expert 50 ans/domaine + vision transverse via RAG partage', NULL, 'best_practice', 0.90, 'prime', 'system'),
('PRIME_40: Le KeiroAI approaching 8000 learnings: le systeme d intelligence collective des agents est maintenant l un des plus riches du marche SaaS marketing IA.', 'KeiroAI ~8000 learnings: intelligence collective parmi les plus riches du marche', 'ceo', 'insight', 0.92, 'prime', 'system')
